import logo from './logo.svg';
import './App.css';
import './categories.style.scss'

function App() {
  const categories = [
    {
      id : 1,
      title : "Hats"
    },
    {
      id : 2,
      title : "Jackets"
    },
    {
      id : 3,
      title : "Sneakers"
    },
    {
      id : 4,
      title : "Mens"
    },
    {
      id : 5,
      title : "Womens"
    },
  ]
  return (
    <div className='categories-container'>
      {categories.map(({id,title})=>
        (
          <div className='category-container' id={id}>
            {/* <img/> */}
            <div className='category-body-container'>
              <h2>{title}</h2>
              <p>Shop Now</p>
            </div>
          </div>
        )
      )}
    </div>

  );
}

export default App;
